import { logger } from '@/lib/logger';

export function myFunction(fieldId: number) {
  logger.info('Processing field', 'lib/game/my-file.ts', 'myFunction', { fieldId });
  try {
    // ...
  } catch (err) {
    logger.error('Failed to process field', 'lib/game/my-file.ts', 'myFunction', err, { fieldId });
  }
}
